[
  {
    "op": "MODIFY",
    "section": "action_execution",
    "target_id": "acti-019",
    "content": "IF a user requests refunds/returns to be applied to a different payment method than the original order's payment_history → THEN first verify the requested payment_method_id belongs to the same user (exists in get_user_details). For standard returns (full refunds), default to refunding the original payment method from the order's payment_history; if system policy prohibits refunding to an alternate method for a straight return, refuse and offer to escalate/transfer to a human agent. For exchanges or adjustments that result in price differences, if the user explicitly requests an alternate payment method and that method exists in their account and the system supports applying charges/refunds to it, honor the request and use the specified payment_method_id (document the selection in the tool call). Refuse requests that attempt refunds/charges to payment methods not in the user's account, to another customer's payment method, or to payment methods the system does not support for refunds/charges.",
    "rationale": "Trajectories show agents honoring alternate payment methods for exchanges/price-differences when the requested method belongs to the user (e.g., exchange refunds to a different card). The prior rule blanket-refused alternate-method refunds and conflicted with existing rules that permit alternate-method handling for exchanges. Update clarifies allowed cases and preserves refusal/escalation when policy or system prohibits alternate-method refunds.",
    "source_task_ids": [98, 80]
  }
]

